import type { AdminCommentItem, PaginatedResponse } from '~/types/admin'

const PAGE_SIZE = 8

type CommentStatusFilter = 'all' | 'pending' | 'approved' | 'rejected'

interface LoadCommentsOptions {
  page: number
  keyword: string
  status: CommentStatusFilter
}

export function useAdminComments() {
  const { adminApiFetch } = useAdminSession()

  // 状态
  const items = ref<AdminCommentItem[]>([])
  const total = ref(0)
  const loading = ref(false)
  const error = ref('')
  const busyId = ref<string | null>(null)
  const selectedIds = ref<string[]>([])

  // 筛选条件
  const keyword = ref('')
  const status = ref<CommentStatusFilter>('all')
  const page = ref(1)

  // 计算属性
  const totalPages = computed(() => Math.max(1, Math.ceil(total.value / PAGE_SIZE)))
  const pendingCount = computed(() => items.value.filter(item => item.status === 'pending').length)

  // 构建查询 URL
  function buildCommentsPath(input: LoadCommentsOptions) {
    const params = new URLSearchParams({
      page: String(input.page),
      pageSize: String(PAGE_SIZE),
      sortBy: 'createdAt',
      sortOrder: 'desc',
    })

    if (input.keyword.trim()) {
      params.set('keyword', input.keyword.trim())
    }

    if (input.status !== 'all') {
      params.set('status', input.status)
    }

    return `/api/v1/admin/comments?${params.toString()}`
  }

  // 加载评论列表
  async function loadComments() {
    loading.value = true
    error.value = ''

    try {
      const result = await adminApiFetch<PaginatedResponse<AdminCommentItem>>(
        buildCommentsPath({ page: page.value, keyword: keyword.value, status: status.value }),
      )

      items.value = result.list
      total.value = result.total
    }
    catch (e) {
      error.value = e instanceof Error ? e.message : '加载评论失败'
    }
    finally {
      loading.value = false
    }
  }

  // 刷新评论
  async function reloadComments() {
    await loadComments()
  }

  // 更新单条评论
  function syncItem(updated: AdminCommentItem) {
    const idx = items.value.findIndex(item => item.id === updated.id)
    if (idx !== -1) {
      items.value[idx] = updated
    }
  }

  // 移除评论
  function removeItem(commentId: string) {
    items.value = items.value.filter(item => item.id !== commentId)
    total.value = Math.max(0, total.value - 1)
    selectedIds.value = selectedIds.value.filter(id => id !== commentId)
  }

  // 审核评论
  async function reviewComment(
    commentId: string,
    nextStatus: 'pending' | 'approved' | 'rejected',
    rejectReason?: string | null,
  ) {
    busyId.value = commentId
    error.value = ''

    try {
      const result = await adminApiFetch<AdminCommentItem>(
        `/api/v1/admin/comments/${commentId}/review`,
        {
          method: 'PATCH',
          body: JSON.stringify({
            status: nextStatus,
            rejectReason: rejectReason ?? null,
          }),
        },
      )

      syncItem(result)
      await reloadComments()
      return result
    }
    catch (e) {
      error.value = e instanceof Error ? e.message : '审核评论失败'
      return null
    }
    finally {
      busyId.value = null
    }
  }

  // 删除评论
  async function deleteComment(comment: AdminCommentItem) {
    if (!confirm('确认删除这条评论吗？删除后无法恢复。')) {
      return false
    }

    busyId.value = comment.id
    error.value = ''

    try {
      await adminApiFetch(`/api/v1/admin/comments/${comment.id}`, {
        method: 'DELETE',
      })

      removeItem(comment.id)
      await reloadComments()
      return true
    }
    catch (e) {
      error.value = e instanceof Error ? e.message : '删除评论失败'
      return false
    }
    finally {
      busyId.value = null
    }
  }

  // 批量操作
  async function runBulkAction(
    action: 'approved' | 'rejected' | 'delete',
    targetIds?: string[],
  ) {
    const targets = targetIds ?? selectedIds.value

    if (targets.length === 0) {
      return
    }

    if (action === 'delete') {
      if (!confirm(`确认删除选中的 ${targets.length} 条评论吗？`)) {
        return
      }
    }

    error.value = ''
    busyId.value = 'bulk'

    try {
      if (action === 'delete') {
        for (const id of targets) {
          await adminApiFetch(`/api/v1/admin/comments/${id}`, { method: 'DELETE' })
          removeItem(id)
        }
        selectedIds.value = []
        await reloadComments()
        return
      }

      const results = await Promise.all(
        targets.map(id =>
          adminApiFetch<AdminCommentItem>(`/api/v1/admin/comments/${id}/review`, {
            method: 'PATCH',
            body: JSON.stringify({
              status: action,
              rejectReason: action === 'rejected' ? '批量驳回' : null,
            }),
          }),
        ),
      )

      results.forEach(syncItem)
      await reloadComments()
    }
    catch (e) {
      error.value = e instanceof Error ? e.message : '批量操作失败'
    }
    finally {
      busyId.value = null
    }
  }

  // 全选切换
  function toggleAllSelection(allSelected: boolean) {
    if (allSelected) {
      selectedIds.value = selectedIds.value.filter(
        id => !items.value.some(item => item.id === id),
      )
    }
    else {
      selectedIds.value = Array.from(
        new Set([...selectedIds.value, ...items.value.map(item => item.id)]),
      )
    }
  }

  // 单选切换
  function toggleSelection(id: string, checked: boolean) {
    if (checked) {
      selectedIds.value = Array.from(new Set([...selectedIds.value, id]))
    }
    else {
      selectedIds.value = selectedIds.value.filter(i => i !== id)
    }
  }

  // 状态筛选变化
  function setStatusFilter(newStatus: CommentStatusFilter) {
    status.value = newStatus
    page.value = 1
  }

  // 搜索变化
  function setKeyword(newKeyword: string) {
    keyword.value = newKeyword
    page.value = 1
  }

  // 页码变化
  function setPage(newPage: number) {
    page.value = newPage
  }

  // 重置筛选
  function resetFilters() {
    keyword.value = ''
    status.value = 'all'
    page.value = 1
  }

  return {
    // 状态
    items,
    total,
    loading,
    error,
    busyId,
    selectedIds,
    keyword,
    status,
    page,

    // 计算属性
    totalPages,
    pendingCount,

    // 方法
    loadComments,
    reloadComments,
    reviewComment,
    deleteComment,
    runBulkAction,
    toggleAllSelection,
    toggleSelection,
    setStatusFilter,
    setKeyword,
    setPage,
    resetFilters,
  }
}
<script setup lang="ts">
definePageMeta({
  layout: 'admin',
  middleware: 'admin-auth',
})

useHead({
  title: '评论管理',
})

const {
  items,
  total,
  loading,
  error,
  busyId,
  selectedIds,
  keyword,
  status,
  page,
  totalPages,
  pendingCount,
  loadComments,
  reviewComment,
  deleteComment,
  runBulkAction,
  toggleAllSelection,
  toggleSelection,
  setStatusFilter,
  setKeyword,
  setPage,
} = useAdminComments()

// 选中的评论详情
const selectedId = ref<string | null>(null)
const selectedComment = computed(() =>
  items.value.find(item => item.id === selectedId.value) ?? items.value[0] ?? null,
)

// 全选状态
const allVisibleSelected = computed(() =>
  items.value.length > 0 && items.value.every(item => selectedIds.value.includes(item.id)),
)

// 加载数据
watch([page, keyword, status], () => {
  loadComments()
}, { immediate: true })

// 选中第一条
watch(items, (newItems) => {
  if (newItems.length > 0 && !selectedId.value) {
    selectedId.value = newItems[0].id
  }
})

function handleStatusChange(newStatus: 'all' | 'pending' | 'approved' | 'rejected') {
  setStatusFilter(newStatus)
}

function handleKeywordChange(value: string) {
  setKeyword(value)
}

async function handleApprove(comment: typeof selectedComment.value) {
  if (comment) {
    await reviewComment(comment.id, 'approved')
    selectedId.value = comment.id
  }
}

async function handleReject(comment: typeof selectedComment.value) {
  if (comment) {
    await reviewComment(comment.id, 'rejected', '内容不符合发布规则')
    selectedId.value = comment.id
  }
}

async function handleReset(comment: typeof selectedComment.value) {
  if (comment) {
    await reviewComment(comment.id, 'pending')
    selectedId.value = comment.id
  }
}

async function handleDelete(comment: typeof selectedComment.value) {
  if (comment) {
    const success = await deleteComment(comment)
    if (success && selectedId.value === comment.id) {
      selectedId.value = items.value[0]?.id ?? null
    }
  }
}
</script>

<template>
  <div class="space-y-6">
    <AdminPageHeader title="评论管理" description="按状态筛选评论，并支持单条或批量审核。" />

    <!-- 搜索和筛选 -->
    <div class="admin-card p-4">
      <div class="flex flex-col gap-3 xl:flex-row xl:items-center xl:justify-between">
        <AdminSearchField v-model="keyword" placeholder="搜索昵称、内容或文章标题" @update:model-value="handleKeywordChange" />

        <div class="flex flex-wrap gap-2">
          <button
            class="admin-button-secondary"
            :class="{ 'admin-button-primary': status === 'all' }"
            @click="handleStatusChange('all')"
          >
            全部
          </button>
          <button
            class="admin-button-secondary"
            :class="{ 'admin-button-primary': status === 'pending' }"
            @click="handleStatusChange('pending')"
          >
            待审核
          </button>
          <button
            class="admin-button-secondary"
            :class="{ 'admin-button-primary': status === 'approved' }"
            @click="handleStatusChange('approved')"
          >
            已通过
          </button>
          <button
            class="admin-button-secondary"
            :class="{ 'admin-button-primary': status === 'rejected' }"
            @click="handleStatusChange('rejected')"
          >
            已驳回
          </button>
        </div>
      </div>
    </div>

    <!-- 错误提示 -->
    <div v-if="error" class="admin-card border border-rose-200 bg-rose-50 px-4 py-3 text-sm text-rose-600">
      {{ error }}
    </div>

    <!-- 评论列表和详情 -->
    <section class="grid gap-6 xl:grid-cols-[1.15fr_0.85fr]">
      <!-- 列表 -->
      <div class="admin-card overflow-hidden">
        <div class="flex flex-wrap items-center justify-between gap-3 border-b border-[var(--admin-border)] px-5 py-4">
          <div>
            <p class="text-sm font-semibold text-slate-900">当前页 {{ items.length }} 条</p>
            <p class="text-xs text-slate-500">{{ pendingCount }} 条待审核</p>
          </div>
          <div class="flex flex-wrap gap-2">
            <button
              class="admin-button-secondary"
              :disabled="loading || items.length === 0"
              @click="toggleAllSelection(allVisibleSelected)"
            >
              {{ allVisibleSelected ? '取消本页全选' : '本页全选' }}
            </button>
            <button
              class="admin-button-primary"
              :disabled="loading || selectedIds.length === 0 || busyId === 'bulk'"
              @click="runBulkAction('approved')"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7" />
              </svg>
              批量通过
            </button>
            <button
              class="admin-button-secondary"
              :disabled="loading || selectedIds.length === 0 || busyId === 'bulk'"
              @click="runBulkAction('rejected')"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              批量驳回
            </button>
            <button
              class="admin-button-danger"
              :disabled="loading || selectedIds.length === 0 || busyId === 'bulk'"
              @click="runBulkAction('delete')"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              批量删除
            </button>
          </div>
        </div>

        <div class="overflow-x-auto">
          <table class="w-full border-collapse">
            <thead>
              <tr class="border-b border-[var(--admin-border)] bg-slate-50/90 text-left">
                <th class="px-5 py-4 text-xs font-semibold uppercase tracking-[0.14em] text-slate-400">选择</th>
                <th class="px-5 py-4 text-xs font-semibold uppercase tracking-[0.14em] text-slate-400">评论</th>
                <th class="px-5 py-4 text-xs font-semibold uppercase tracking-[0.14em] text-slate-400">状态</th>
                <th class="px-5 py-4 text-xs font-semibold uppercase tracking-[0.14em] text-slate-400">时间</th>
                <th class="px-5 py-4 text-xs font-semibold uppercase tracking-[0.14em] text-slate-400">操作</th>
              </tr>
            </thead>
            <tbody>
              <tr v-if="loading">
                <td class="px-5 py-10 text-sm text-slate-400" colspan="5">
                  正在加载评论...
                </td>
              </tr>
              <tr v-else-if="items.length === 0">
                <td class="px-5 py-10 text-sm text-slate-400" colspan="5">
                  暂无符合筛选条件的评论。
                </td>
              </tr>
              <tr
                v-for="comment in items"
                v-else
                :key="comment.id"
                class="border-b border-[var(--admin-border)] transition hover:bg-slate-50"
                :class="{ 'bg-blue-50/50': selectedComment?.id === comment.id }"
              >
                <td class="px-5 py-4">
                  <input
                    :checked="selectedIds.includes(comment.id)"
                    type="checkbox"
                    @change="toggleSelection(comment.id, ($event.target as HTMLInputElement).checked)"
                  >
                </td>
                <td class="px-5 py-4">
                  <button class="block text-left" type="button" @click="selectedId = comment.id">
                    <p class="text-sm font-semibold text-slate-900">{{ comment.nickname }}</p>
                    <p class="mt-1 line-clamp-2 text-sm leading-7 text-slate-500">{{ comment.content }}</p>
                    <p class="mt-2 text-xs text-slate-400">{{ comment.article.title }}</p>
                  </button>
                </td>
                <td class="px-5 py-4">
                  <AdminStatusBadge
                    :tone="comment.status === 'approved' ? 'success' : comment.status === 'pending' ? 'warning' : 'danger'"
                  >
                    {{ comment.status === 'approved' ? '已通过' : comment.status === 'pending' ? '待审核' : '已驳回' }}
                  </AdminStatusBadge>
                </td>
                <td class="px-5 py-4 text-sm text-slate-500">
                  {{ new Date(comment.createdAt).toLocaleDateString('zh-CN') }}
                </td>
                <td class="px-5 py-4">
                  <button class="admin-button-secondary" type="button" @click="selectedId = comment.id">
                    <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" />
                      <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" />
                    </svg>
                    查看
                  </button>
                </td>
              </tr>
            </tbody>
          </table>
        </div>

        <AdminPagination
          label="评论分页"
          :page="Math.min(page, totalPages)"
          :total="total"
          :total-pages="totalPages"
          @update:page="setPage"
        />
      </div>

      <!-- 详情 -->
      <div class="admin-card p-6">
        <template v-if="selectedComment">
          <div class="flex items-start justify-between gap-3">
            <div>
              <p class="text-lg font-semibold text-slate-900">{{ selectedComment.nickname }}</p>
              <p class="mt-1 text-sm text-slate-500">来自 {{ selectedComment.article.title }}</p>
            </div>
            <AdminStatusBadge
              :tone="selectedComment.status === 'approved' ? 'success' : selectedComment.status === 'pending' ? 'warning' : 'danger'"
            >
              {{ selectedComment.status === 'approved' ? '已通过' : selectedComment.status === 'pending' ? '待审核' : '已驳回' }}
            </AdminStatusBadge>
          </div>

          <div class="mt-6 rounded-[4px] bg-slate-50 p-5">
            <p class="text-sm leading-8 text-slate-700">{{ selectedComment.content }}</p>
          </div>

          <div class="mt-6 space-y-3 text-sm text-slate-500">
            <p>创建时间: {{ new Date(selectedComment.createdAt).toLocaleString('zh-CN') }}</p>
            <p>邮箱: {{ selectedComment.email }}</p>
            <p>网站: {{ selectedComment.website || '未填写' }}</p>
            <p>回复层级: {{ selectedComment.parent ? `回复 ${selectedComment.parent.nickname}` : '一级评论' }}</p>
            <p v-if="selectedComment.rejectReason">驳回原因: {{ selectedComment.rejectReason }}</p>
          </div>

          <div class="mt-6 grid gap-3 sm:grid-cols-2">
            <button
              class="admin-button-primary"
              :disabled="busyId === selectedComment.id || busyId === 'bulk'"
              @click="handleApprove(selectedComment)"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M5 13l4 4L19 7" />
              </svg>
              通过
            </button>
            <button
              class="admin-button-secondary"
              :disabled="busyId === selectedComment.id || busyId === 'bulk'"
              @click="handleReset(selectedComment)"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
              </svg>
              设为待审核
            </button>
            <button
              class="admin-button-danger"
              :disabled="busyId === selectedComment.id || busyId === 'bulk'"
              @click="handleReject(selectedComment)"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M18.364 18.364A9 9 0 005.636 5.636m12.728 12.728A9 9 0 015.636 5.636m12.728 12.728L5.636 5.636" />
              </svg>
              驳回
            </button>
            <button
              class="admin-button-secondary"
              :disabled="busyId === selectedComment.id || busyId === 'bulk'"
              @click="handleDelete(selectedComment)"
            >
              <svg class="h-4 w-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
              删除
            </button>
          </div>

          <NuxtLink
            class="mt-6 inline-flex text-sm font-medium text-blue-600 hover:underline"
            :to="`/articles/${selectedComment.article.slug}`"
            target="_blank"
          >
            打开文章
          </NuxtLink>
        </template>

        <div v-else class="flex h-full min-h-64 items-center justify-center text-sm text-slate-400">
          请选择一条评论查看详情
        </div>
      </div>
    </section>
  </div>
</template>
